567	    /**@ch 裝置旋轉 */
568	    OnRotation() {
569	        // 取得螢幕寬高
570	        let size = screen.windowSize;
571	
572	        // 判斷橫版
573	        if (!this.IsLockRotation) {
574	            this.m_isLandscape = size.width > size.height;
575	        }
576	
577	        // 預設值
578	        let designWidth = WIDTH;
579	        let designHeight = HEIGHT;
580	        let policy = ResolutionPolicy.FIXED_WIDTH;
581	        let animation = this.m_isLandscape ? ROTATION_ANIMATION_LANDSCAPE : ROTATION_ANIMATION_PORTRAIT;
582	
583	        // 直版
584	        if (!this.m_isLandscape) {
585	            designWidth = HEIGHT;
586	            designHeight = WIDTH;
587	            // 依照高寬比決定策略
588	            policy = (size.height / size.width <= WIDTH / HEIGHT)
589	                ? ResolutionPolicy.FIXED_HEIGHT
590	                : ResolutionPolicy.FIXED_WIDTH;
591	        }
592	        // 橫版
593	        else {
594	            // 依照寬高比決定策略
595	            policy = (size.width / size.height <= WIDTH / HEIGHT)
596	                ? ResolutionPolicy.FIXED_WIDTH
597	                : ResolutionPolicy.FIXED_HEIGHT;
598	        }
599	
600	        // 旋轉動畫
601	        this.m_mainGameAnimation?.play(animation);
602	
603	        log("GameView OnRotation :", this.m_isLandscape ? "橫版" : "直版");
604	
605	        view.setDesignResolutionSize(designWidth, designHeight, policy);
606	        newBottombarManager.OnRotation(this.m_isLandscape, () => { }, true);
607	        newExtraManager?.OnRotation(this.m_isLandscape, true, false);
608	        msgBoxManager?.OnRotate(this.m_isLandscape);
609	
610	        /**@ch 發送裝置旋轉事件 */
611	        eventManager.Dispatch(GAME_EVENT.DEVICE_ROTATION);
612	    }
