619	    private SetStateMachine() {
620	        let states = {};
621	        states[ CommonState.WAIT_RES ] = new WaitResState( this );
622	        states[ Game_Define.GameState.WAIT_READY ] = new WaitReadyState( this );
623	        states[ Game_Define.GameState.PLATE_SHOW ] = new PlateShowState( this );
624	        states[ Game_Define.GameState.FEATURE_SHOW ] = new FeatureShowState( this );
625	        states[ Game_Define.GameState.UNSHOW_PREPARE ] = new UnshowPrepareState( this );
626	        states[ CommonState.IDLE ] = new IdleState( this );
627	        states[ CommonState.SPIN ] = new SpinState( this );
628	        states[ Game_Define.GameState.AWARD ] = new AwardState( this );
629	        states[ Game_Define.GameState.ROUND_SHOW_END ] = new RoundShowEndState( this );
630	        states[ CommonState.CHECK_STATE ] = new CheckState( this );
631	        states[ Game_Define.GameState.ROUND_END ] = new RoundEndState( this );
632	        states[ Game_Define.GameState.ENTER_FREE ] = new EnterFreeState( this );
633	        states[ Game_Define.GameState.CHECK_JP ] = new CheckJpState( this );
634	        states[ Game_Define.GameState.EFFECT_START ] = new EffectStartState( this );
