938	    private BarTouchCb(event: Event) {
939	        // log("bar event", event);
940	        let name = event?.target?.name;
941	        // log("bar event", name);
942	        
943	        switch (name) {
944	            case this.m_plateSpinBtn?.node.name:
945	                if (tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)) {
946	                    break;
947	                }
948	
949	                if (stateManager.Current() === CommonState.IDLE) {
950	                    if (!this.m_isFirstPlateSpin) {
951	                        this.m_spinClickEvent = Define.BTN_CLICK_EVENT.CLICK_PLATE;
952	                        this.ClickSpin();
953	                    }
954	                    else {
955	                        this.m_isFirstPlateSpin = false;
956	                        let setting: MsgBoxSetting = {} as MsgBoxSetting;
957	                        setting.contextKey = Define.StringKey.MSGBOX_TOUCHPANEL_SPIN;
958	                        setting.titleKey = Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO;
959	                        setting.showCancelBtn = false;
960	                        setting.showConfirmBtn = true;
961	                        setting.showCloseBtn = true;
962	                        setting.confirmCB = () => {
963	                            this.m_spinClickEvent = Define.BTN_CLICK_EVENT.CLICK_PLATE;
964	                            this.ClickSpin();
965	                        };
966	                        msgBoxManager.PushMessageBoxSetting(setting);
967	                    }
968	                }
969	                else {
970	                    if (this.CanPlateStop) {
971	                        this.ClickStop();
972	                    }
973	                }
974	                break;
975	            case BottomBar_UIName.BTN_SPIN:
976	            case BottomBar_UIName.BTN_SPINSTOP:
977	                if (stateManager.Current() === CommonState.IDLE) {
978	                    this.m_spinClickEvent = Define.BTN_CLICK_EVENT.SPIN;
979	                    this.ClickSpin();
980	                }
981	                else if (this.CanPlateStop) {
982	                    this.ClickStop();
983	                }
984	                break;
985	            case BottomBar_UIName.BTN_AUTOPLAY:
986	                if (!tools.CheckSwitchOff(SwitchOffKeyDefine.ShowAutoSetting)) {
987	                    break;
988	                }
989	            // eslint-disable-next-line no-fallthrough
990	            case BottomBar_UIName.BTN_WISEAUTOPLAY:
991	                // 開啟智慧自動玩面板
992	                if (newBottombarManager.IsAutoSpin) {
993	                    newBottombarManager.ShowAutoPlayState(false);
994	                    newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_CANCEL);
995	                }
996	                newBottombarManager.ShowAutoplaySettingView(newBottombarManager.GetChips());
997	                break;
998	            case BetValueChange: {
999	                // TODO 若切換Bet時有需要額外處理，可在這裡處理或送事件
1000	                eventManager.Dispatch( GAME_EVENT.CHANGE_BET, newBottombarManager.GetNowBetValue() );
1001	                break;
1002	            }
1003	            case BottomBar_UIName.BTN_AUTOSTOP_C:
1004	            case BottomBar_UIName.BTN_AUTOSTOP:
1005	                // 按下取消自動按鍵
1006	                newBottombarManager.ShowAutoPlayState(false);
1007	                newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_CANCEL);
1008	                /*
1009	                if (this.BigWin &&!this.BigWin.IsEnd) {
1010	                    newBottombarManager.SetSpinState(SlotBottomBarState.SKIP_SMALL_FLASH_AUTOPLAY);
1011	                }
1012	                */
1013	                break;
1014	            default: {
1015	                let betIndex = Number(name);
1016	                if (betIndex === -1) {
1017	                    let bet = newBottombarManager.GetNowBetValue();
1018	                    betIndex = newBottombarManager.FindBetIndexByValue(bet);
