1042	    /**@ch 取得symbol的idx */
1043	    private GetIdx(name: string) {
1044	        // reg 需依需求調整
1045	        let reg = /Symbol_(\d{2})/g;
1046	        let result: number[] = [];
1047	        let res = reg.exec(name);
1048	
1049	        // result 大小依遊戲需求改變(MEGA Way會有兩個參數)
1050	        for (let i = 0; i < res.length; ++i) {
1051	            let value = Number(res[i]);
1052	            if (!isNaN(value)) {
1053	                result.push(value);
1054	            }
1055	        }
1056	        return result;
1057	    }
