1059	    /**@ch 動態載入symbol */
1060	    private LoadSymbol() {
1061	        let path = this.m_loadPath.trim() + "Img/Symbol";
1062	        Define.GameBundle.loadDir(
1063	            path,
1064	            SpriteFrame,
1065	            (error: Error, assets: SpriteFrame[]) => {
1066	                if (error) {
1067	                    this.LoadSymbol();
1068	                    return;
1069	                }
1070	
1071	                // 過濾掉檔名中沒有 Symbol_XX 格式的資源
1072	                assets = assets.filter((asset: SpriteFrame) => {
1073	                    let idx = this.GetIdx(asset.name);
1074	                    return idx.length > 0;
1075	                });
1076	
1077	                assets.sort((a: SpriteFrame, b: SpriteFrame) => {
1078	                    let AIdx: number[] = this.GetIdx(a.name);
1079	                    let BIdx: number[] = this.GetIdx(b.name);
1080	
1081	                    if (AIdx[0] < BIdx[0]) {
1082	                        return -1;
1083	                    }
1084	                    else if (AIdx[0] > BIdx[0]) {
1085	                        return 1;
1086	                    }
1087	                    else {
1088	                        return 0;
1089	                    }
1090	                });
1091	
1092	                this.m_symbolSpriteFrames = assets;
1093	
1094	                // 空節點
1095	                this.m_symbolSpriteFrames.push(null);
1096	
1097	                // 設定盤面結構（在 CreateSymbol 前呼叫）
1098	                //   Standard 轉輪：REEL_LAYOUT_PRESETS.standard（3 層）
1099	                //   DropEntry 玩法：REEL_LAYOUT_PRESETS.dropEntry（1 層）
1100	                this.m_slotReels?.SetLayoutConfig(REEL_LAYOUT_PRESETS.standard);
1101	                this.SlotReels?.CreateSymbol();
1102	            });
1103	    }
