import Long from "long";
import protobuf from "protobufjs";

//=============================================================
// 引擎
import {
_decorator, Component, Node, Button, log, Tween, KeyCode, Input, input, EventKeyboard,
SpriteAtlas, ResolutionPolicy, view, Event, sys, EventTouch, screen, SpriteFrame, Font, Animation, AudioClip, error, Sprite,
BufferAsset
} from "cc";

//=============================================================
// 框架
import { AstarteInit } from "db://astarte-framework/System";
import { SwitchOffKeyDefine } from "db://astarte-framework/License/LicenseSetting";
import { ConnectionManager } from "db://astarte-framework/net/ConnectionManager";
import {
msgBoxManager, MsgBoxSetting, localeStringManager, newBottombarManager, newExtraManager,
SlotBottomBarState, stateManager, BottomBar_UIName, commonGameManager, eventManager, CommonEventName, giftCodeManager,
backpackManager, missionManager, gaiaManager, iframeCommandManager, AutoplayType_ORG, BetValueChange, buyBonusManager, debrisManager
} from "db://astarte-framework/Managers";
import { CommonBuyBonus } from "db://astarte-framework/Component/BuyBonus/CommonBuyBonus";
import ManualComponent from "db://astarte-framework/Component/ManualComponent";
import { tools, Define, CommonState } from "db://astarte-framework/utilis";

//=============================================================
// 協定 protocol
import protocol from "./Proto";
import type { ar2lpProto } from "./Proto";
import { RecoverSpinAck } from "./RecoverSpinAck";

//=============================================================
// 遊戲介面
import { SlotReel } from "./SlotReels";

//=============================================================
// 遊戲定義
import Game_Define, { GAME_EVENT, Symbol, SymbolInfo } from "./Game_Define";

//=============================================================
// 遊戲效果
//import EffectPlate from "./EffectPlate";
import EffectPlate from "./EffectPlate/EffectPlate";

//=============================================================
// 遊戲狀態
import { WaitResState } from "./GameState/WaitResState";
import { WaitReadyState } from "./GameState/WaitReadyState";
import { PlateShowState } from "./GameState/PlateShowState";
import { IdleState } from "./GameState/IdleState";
import { SpinState } from "./GameState/SpinState";
import { AwardState } from "./GameState/AwardState";
import { RoundEndState } from "./GameState/RoundEndState";
import { RoundShowEndState } from "./GameState/RoundShowEndState";
import { UnshowPrepareState } from "./GameState/UnshowPrepareState";
import { FeatureShowState } from "./GameState/FeatureShowState";
import { CheckState } from "./GameState/CheckState";
import { EnterFreeState } from "./GameState/EnterFreeState";
import { EffectStartState } from "./GameState/EffectStartState";
import { ScatterShowState } from "./GameState/ScatterShowState";
import { AddFreeState } from "./GameState/AddFreeState";
import { FullRewardState } from "./GameState/FullRewardState";
import { LeaveFreeState } from "./GameState/LeaveFreeState";
import { ExplodeState } from "./GameState/ExplodeState";
import { MatchingPatchUpState } from "./GameState/MatchingPatchUpState";
import { CheckJpState } from "./GameState/CheckJpState";
import { CoinState } from "./GameState/CoinState";

//=============================================================
// 音樂音效
import { AudioManager } from "./Audio/AudioManager";

//=============================================================
// 其他
import { Common } from "./Common/Common";
import BigWinComponent from "db://astarte-framework/Component/BigWinComponent";
import { GAME_INTRO_MANAGER_EVENT } from "./GameIntroManager";
import { ReelDevTool } from "./ReelDevTool";
import { ExplodeData, FillData } from "./FillStrategy/IFillStrategy";
import { REEL_LAYOUT_PRESETS } from "./ReelLayoutConfig";


/**@ch 設計寬度 */
const WIDTH = 1136;

/**@ch 設計高度 */
const HEIGHT = 640;

/**@ch 旋轉動畫 橫版 */
const ROTATION_ANIMATION_LANDSCAPE = "MainGame_L";

/**@ch 旋轉動畫 直版 */
const ROTATION_ANIMATION_PORTRAIT = "MainGame_S";

const { ccclass, property } = _decorator;

@ccclass('GameView')
export default class GameView extends Component {
    //#region 變數
    @property( {
        type: Animation,
        tooltip: "主遊戲動畫"
    } )
    private m_mainGameAnimation: Animation = null;

    @property( {
        type: CommonBuyBonus,
        tooltip: "購買Bonus"
    } )
    private m_buyBonus: CommonBuyBonus = null;
    public get BuyBonus(): CommonBuyBonus
    {
        return this.m_buyBonus;
    }

    @property( {
        type: SlotReel,
        tooltip: "轉輪"
    } )
    private m_slotReels: SlotReel = null;
    public get SlotReels(): Readonly<SlotReel>
    {
        return this.m_slotReels;
    }

    @property( {
        type: ReelDevTool,
        tooltip: "轉輪測試工具（開發用，上線前移除）"
    } )
    private m_reelDevTool: ReelDevTool = null;

    @property( {
        type: EffectPlate,
        tooltip: "盤面表演"
    } )
    private m_effectPlate: EffectPlate = null;
    public get EffectPlate(): EffectPlate
    {
        return this.m_effectPlate;
    }

    @property( {
        type: Button,
        tooltip: "盤面spin"
    } )
    private m_plateSpinBtn: Button = null;

    @property( {
        type: SpriteAtlas,
        tooltip: "標題合圖"
    } )
    private m_titleSpriteAtlas: SpriteAtlas = null;

    @property( {
        type: ManualComponent,
        tooltip: "ManualComponent"
    } )
    private m_manual: ManualComponent = null;
    public get Manual()
    {
        return this.m_manual;
    }

    /*************************************************** 各遊戲特色區 ***************************************************/

    @property({
        type: BigWinComponent,
        tooltip: "BigWin 報獎組件"
    })
    private m_bigWinComp: BigWinComponent = null;
    public get BigWin() { return this.m_bigWinComp; }

    @property({
        type: Node,
        tooltip: "SmallWin 小報獎節點"
    })
    private m_smallWinNode: Node = null;
    public get SmallWin() { return this.m_smallWinNode; }

    @property({
        type: Node,
        tooltip: "FG 進場演出節點（掛 sp.Skeleton）"
    })
    private m_fgDeclareNode: Node = null;
    public get FgDeclareNode() { return this.m_fgDeclareNode; }

    @property({
        type: Node,
        tooltip: "FG 結算演出節點（掛 sp.Skeleton）"
    })
    private m_fgComplimentNode: Node = null;
    public get FgComplimentNode() { return this.m_fgComplimentNode; }

    @property({
        type: String,
        tooltip: "動態載入資源路徑，game資料夾以後的路徑，結尾帶/，一般版留空"
    })
    private m_loadPath = "";

    //自動玩
    private m_autoplayInfos: AutoplayType_ORG = null;
    public get AutoplayInfos(): AutoplayType_ORG
    {
        return this.m_autoplayInfos;
    }

    //狀態
    private m_isLandscape: boolean = false;
    public get IsLandscape(): Readonly<boolean>
    {
        return this.m_isLandscape;
    }   

    /**@ch 是否鎖定旋轉 */
    private m_isLockRotation: boolean = false;
    public get IsLockRotation(): boolean {
        return this.m_isLockRotation;
    }
    public set IsLockRotation(v: boolean) {
        this.m_isLockRotation = v;
    }

    private m_isBottombarFinished: boolean = false;
    public get IsBottombarFinished(): boolean
    {
        return this.m_isBottombarFinished;
    }

    private m_isFirstPlateSpin: boolean = true;

    private m_isHardStop: boolean = false;
    public set IsHardStop( v: boolean )
    {
        this.m_isHardStop = v;
    }

    public get IsHardStop(): boolean
    {
        return this.m_isHardStop;
    }

    //回應
    private m_spinAck: ar2lpProto.ISpinAck = null;
    public get SpinAck(): Readonly<ar2lpProto.ISpinAck>
    {
        return this.m_spinAck;
    }
    public set SpinAck( v: ar2lpProto.ISpinAck )
    {
        this.m_spinAck = v;
    }

    private m_unshowSpinAck: ar2lpProto.ISpinAck = null;
    public set UnshowSpinAck( v: ar2lpProto.ISpinAck )
    {
        this.m_unshowSpinAck = v;
    }
    public get UnshowSpinAck(): ar2lpProto.ISpinAck
    {
        return this.m_unshowSpinAck;
    }
    private m_curPlateIndex: number = -1;
    public get CurPlateIndex(): Readonly<number>
    {
        return this.m_curPlateIndex;
    }
    public set CurPlateIndex( v: number )
    {
        this.m_curPlateIndex = v;
    }

    //log
    private m_spinClickEvent: number = 0;

    /** BGM ID*/
    private m_bgmId: number = null;
    public set BgmId( v: number )
    {
        this.m_bgmId = v;
    }
    public get BgmId(): number
    {
        return this.m_bgmId;
    }

    private m_freeBgmId: number = null;
    public set FreeBgmId( v: number )
    {
        this.m_freeBgmId = v;
    }
    public get FreeBgmId(): number
    {
        return this.m_freeBgmId;
    }

    /** 大獎音效ID*/
    private m_bigWinSoundId: number = null;
    public get BigWnSoundId()
    {
        return this.m_bigWinSoundId;
    }
    public set BigWnSoundId( v: number )
    {
        this.m_bigWinSoundId = v;
    }

    /**@ch 空白鍵按停 */
    private m_canSpaceStop: boolean = true;
    public set CanSpaceStop( v: boolean )
    {
        this.m_canSpaceStop = v;
    }
    public get CanSpaceStop()
    {
        return this.m_canSpaceStop;
    }
    /**@ch 盤面按停 */
    private m_canPlateStop: boolean = true;
    public set CanPlateStop( v: boolean )
    {
        this.m_canPlateStop = v;
    }
    public get CanPlateStop()
    {
        return this.m_canPlateStop;
