    /**@ch 按下停止按鍵 */
    private ClickStop() {
        if (tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)
            || !this.CanSpaceStop
            || !this.CanPlateStop
        ) {
            return;
        }

        if (stateManager.Current() === CommonState.SPIN) {
            if (!newBottombarManager.IsAutoSpin) {

                this.SlotReels?.ClickStopBtn();
                newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP);
            }
            else if (!this.m_isHardStop) {
                this.SlotReels?.ClickStopBtn();
                newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP_IN_AUTOPLAY);
            }

            // 盤面按停
            this.SlotReels?.ClickStopBtn();
        }
        else if (stateManager.Current() === Game_Define.GameState.AWARD) {
            //大獎跳過
            if (newBottombarManager.IsAutoSpin) {
                newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP);
            }
            else {
                newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP);
            }
            // TODO 因為還沒有BigWin，所以先註解
            /*
            this.BigWin?.Stop();
            */
        }
    }

    /**@ch 處理從伺服器接收到的轉輪結果 */
    OnRecvSpinAck( ack, isUnshow = false )
    {
        error( "SpinAck before :", ack );

        let info = RecoverSpinAck.getInstance().RecoverSpinAck( ack );
        console.error( "SpinAck :", info );
        this.SpinAck = info;        

        if ( this.SpinAck.RoundQueue.length > 1 )
        {
            if ( !isUnshow || this.CurPlateIndex === 0 )
            {
                // 檢查第一輪是否為FreeGame 或 RespinGame
                const firstRound = this.SpinAck.RoundQueue[0];
                if (firstRound.FreePlateSymbol.length > 0 && firstRound.NextFeverGameType > 0)
                {
                    this.IsGoingToFree = true;
                }
            }
        }

        this.BuyBonus?.CleanInfo();

        // 地Bar按鈕狀態
        if ( newBottombarManager.IsAutoSpin && !this.IsHardStop )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
        }

        // 設定當局盤面資訊
        this.SetNowRoundInfo( this.SpinAck.RoundQueue[ this.CurPlateIndex ] );

        // ClickStopBtn（快停）已移至 SpinState.OnEnter 的 SetNowRoundInfo 之後，
        // 確保 SetReelTimes 先執行再計算快停時間
        if ( this.IsHardStop )
        {
            newBottombarManager.SetSpinWithSpeed();
        }
        else
        {
            if ( !newBottombarManager.IsAutoSpin )
            {
                newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
            }
        }
    }

