## 常見問題

### Q: 如何讓不同列有不同的掉落延遲？
A: 在子類別的 `fillColumn` 中加入列間延遲：
```typescript
for (let col = 0; col < this.m_columns.length; col++) {
    await this.delay(col * 0.05); // 每列延遲 0.05 秒
    await this.fillColumn(col, ...);
}
```

### Q: 如何加入 NearWin 聽牌效果？
A: NearWin 是 Standard Spin 停輪階段的功能，在 `SlotReels.SetReelTimes()` 中處理，與 FillStrategy 無關。

### Q: Cascade 和 Tumble 的差異在哪？
A: 邏輯結構相同（都是「存活下沉 + 新符號補位 + 陣列重排」三階段），差異在動畫表現：
- Cascade：掉落時間與「實際格數」成正比，每格時間獨立 — 適合中獎線消除
- Tumble：掉落時間「除以總行數」，整列同時抵達 — 適合全盤消除（Ways）

### Q: 為什麼 Cascade 的 explode 階段要排序 deadRows？
A: 因為 `fill` 階段要用 `deadRows[i]` 對應到「視覺上第 i 個頂部空位」，必須由小到大排列，否則新符號會被放到錯誤的載體 cell，重排後索引就亂了。

### Q: 多階段 cascade 中為什麼第二次消除拿到的盤面是對的？
A: 第一次 `fillColumn` 結尾呼叫 `RearrangeSingleCells(mapping)` 重排了 `m_singleCells` 與 `m_symbols`，讓 `m_singleCells[r]` 確實對應到視覺上 row r 的 cell。第二次 explode 用 `HideSymbolByRow(row)` 隱藏的 cell 因此與視覺一致。

### Q: 如何加入乘倍累加（Tumble 常見）？
A: 在 `ExplodeState` 或 `MatchingPatchUpState` 中處理：
```typescript
// ExplodeState.OnEnter() 中
this.m_gameView.CurrentMultiplier += explodeData.positions.length;
```

/**
 * @ch 轉輪盤面結構配置
 * @description 定義 SlotReels 建構時的盤面結構（層數、每列符號數、假符號策略）。
 *              啟動時由 GameView 透過 SlotReel.SetLayoutConfig() 傳入，跑起來後不應變動。
 */

/**@ch 單列配置 */
export interface ColumnConfig {
    /**@ch 該列總 cell 數（含緩衝），Standard 模式通常 > visibleSymbolCount */
    targetSymbolCount: number;
    /**@ch 該列可見行數 */
    visibleSymbolCount: number;
}

/**@ch 盤面結構配置 */
export interface ReelLayoutConfig {
    /**
     * @ch 盤面層數
     * @description
     *   - 1 = 只有中層（DropEntry 等不需要轉輪帶滾動的玩法）
     *   - 3 = 上中下三層（Standard 轉輪滾動需要「無限轉輪帶」視覺）
     */
    plateCount: 1 | 3;

    /**@ch 每列的配置（陣列長度應等於 Game_Define.COL） */
    columns: ColumnConfig[];

    /**
     * @ch 假符號生成策略
     *   - 'random' = 按權重隨機（預設）
     *   - 'repeat' = 從現有可見符號中重複挑選
     */
    fakeSymbolStrategy: 'random' | 'repeat';

    /**@ch 符號替換時機（剩餘圈數） */
    replacementTiming: number;

    /**
     * @ch 不同高度列之間的垂直對齊方式
     * @description 只在「各列 targetSymbolCount 不一致」時會有視覺差異（典型場景：dropEntry 凹字盤面）。
     *   - 'center'（預設）= 短列上下各凹半格，整體置中
     *   - 'top'    = 所有列頂部對齊，短列底部凹整格
     *   - 'bottom' = 所有列底部對齊，短列頂部凹整格
     *
     * Standard 模式下各列 targetSymbolCount 通常相同，此欄位無視覺差異（仍由遮罩決定可見範圍）。
     */
    columnAlignment: 'center' | 'top' | 'bottom';
}

/**
 * @ch 預設配置集合
 * @description 各遊戲可直接套用其中之一，或自訂後傳入 SlotReel.SetLayoutConfig()
 */
export const REEL_LAYOUT_PRESETS = {
    /**@ch 標準轉輪（上中下三層滾動，凹字型可視範圍） */
    standard: {
        plateCount: 3,
        columns: [
            { targetSymbolCount: 5, visibleSymbolCount: 5 }, // col 0
            { targetSymbolCount: 5, visibleSymbolCount: 4 }, // col 1
            { targetSymbolCount: 5, visibleSymbolCount: 4 }, // col 2
            { targetSymbolCount: 5, visibleSymbolCount: 4 }, // col 3
            { targetSymbolCount: 5, visibleSymbolCount: 4 }, // col 4
            { targetSymbolCount: 5, visibleSymbolCount: 5 }, // col 5
        ],
        fakeSymbolStrategy: 'random',
        replacementTiming: 1.0,
        columnAlignment: 'center',
    } as ReelLayoutConfig,

    /**@ch DropEntry 模式（單層，符號從上方掉入） */
    dropEntry: {
        plateCount: 1,
        columns: [
            { targetSymbolCount: 5, visibleSymbolCount: 5 }, // col 0
            { targetSymbolCount: 4, visibleSymbolCount: 4 }, // col 1
            { targetSymbolCount: 4, visibleSymbolCount: 4 }, // col 2
            { targetSymbolCount: 4, visibleSymbolCount: 4 }, // col 3
            { targetSymbolCount: 4, visibleSymbolCount: 4 }, // col 4
            { targetSymbolCount: 5, visibleSymbolCount: 5 }, // col 5
        ],
        fakeSymbolStrategy: 'random',
        replacementTiming: 1.0,
        columnAlignment: 'center',
    } as ReelLayoutConfig,
};

